import React from "react";
import { Circle } from "react-leaflet";

const NIGHT_RADIUS_METERS = 10007500;

function toRadians(degrees) {
  return (degrees * Math.PI) / 180;
}

function toDegrees(radians) {
  return (radians * 180) / Math.PI;
}

function normalizeLongitude(longitude) {
  let value = longitude;

  while (value > 180) {
    value -= 360;
  }
  while (value < -180) {
    value += 360;
  }

  return value;
}

function getSubsolarPoint(date) {
  const julianDate = date.getTime() / 86400000 + 2440587.5;
  const centuries = (julianDate - 2451545.0) / 36525.0;

  const meanLongitude =
    (280.46646 + centuries * (36000.76983 + centuries * 0.0003032)) % 360;
  const meanAnomaly =
    357.52911 + centuries * (35999.05029 - 0.0001537 * centuries);
  const equationOfCenter =
    Math.sin(toRadians(meanAnomaly)) *
      (1.914602 - centuries * (0.004817 + 0.000014 * centuries)) +
    Math.sin(toRadians(2 * meanAnomaly)) * (0.019993 - 0.000101 * centuries) +
    Math.sin(toRadians(3 * meanAnomaly)) * 0.000289;

  const trueLongitude = meanLongitude + equationOfCenter;
  const obliquity = 23.439291 - 0.0130042 * centuries;

  const lambdaRad = toRadians(trueLongitude);
  const obliquityRad = toRadians(obliquity);

  const declination = Math.asin(Math.sin(obliquityRad) * Math.sin(lambdaRad));
  const rightAscension = Math.atan2(
    Math.cos(obliquityRad) * Math.sin(lambdaRad),
    Math.cos(lambdaRad)
  );

  const gmst =
    280.46061837 +
    360.98564736629 * (julianDate - 2451545.0) +
    centuries * centuries * (0.000387933 - centuries / 38710000);

  const subsolarLongitude = normalizeLongitude(toDegrees(rightAscension) - gmst);

  return {
    latitude: toDegrees(declination),
    longitude: subsolarLongitude,
  };
}

export default function DayNightOverlay() {
  const subsolar = getSubsolarPoint(new Date());
  const nightCenter = [
    -subsolar.latitude,
    normalizeLongitude(subsolar.longitude + 180),
  ];

  return (
    <Circle
      center={nightCenter}
      radius={NIGHT_RADIUS_METERS}
      pathOptions={{
        color: "#020617",
        fillColor: "#020617",
        fillOpacity: 0.24,
        weight: 0,
      }}
    />
  );
}
